#!/usr/bin/env python3\nfrom __future__ import annotations\nimport json\nfrom pathlib import Path\n\nLAB = Path('labs/011_goal_language_to_asm_blockout_renderer')\nREPORT = LAB / 'dist' / 'pieces' / 'P03_ELBOW.true_axis_endpoint_3x3_green_line_pit_payload_report.json'\nerrors: list[str] = []\n\nif not REPORT.exists():\n    errors.append(f'missing report: {REPORT}')\nelse:\n    report = json.loads(REPORT.read_text(encoding='utf-8'))\n    if report.get('pieceId') != 'P03_ELBOW':\n        errors.append('report must be for P03_ELBOW')\n    if report.get('orientationCount') != 12:\n        errors.append('P03_ELBOW true-axis report must have 12 orientations')\n    if report.get('pitDimensions') != {'widthCells': 3, 'heightCells': 3, 'depthCells': 10}:\n        errors.append('report must target 3x3x10 pit dimensions')\n    if report.get('projectionContract') != 'WASD_3x3x10':\n        errors.append('report must use WASD_3x3x10 projection contract')\n    if report.get('anchor') != 'centered-in-current-3x3-pit':\n        errors.append('report must place P03 in the current 3x3 pit, not at raw origin')\n    if report.get('summary', {}).get('classification') == 'CONFLICT':\n        errors.append('P03_ELBOW endpoint payload should not be CONFLICT')\n    orientations = report.get('orientations', [])\n    if len(orientations) != report.get('orientationCount'):\n        errors.append('orientation array length must match orientationCount')\n    expected_keys = {'A', 'Q', 'S', 'W', 'D', 'E'}\n    transitions = report.get('transitions', {})\n    for i in range(report.get('orientationCount', 0)):\n        keys = set(transitions.get(str(i), {}).keys())\n        if keys != expected_keys:\n            errors.append(f'orientation {i} transition keys must be A/Q/S/W/D/E, got {sorted(keys)}')\n    total_segments = 0\n    max_segments = 0\n    for item in orientations:\n        segs = item.get('segments', [])\n        total_segments += len(segs)\n        max_segments = max(max_segments, len(segs))\n        if len(segs) > 255:\n            errors.append(f"orientation {item.get('orientationId')} has too many endpoint segments")\n        for cell in item.get('placedCells', []):\n            if not (0 <= cell[0] < 3 and 0 <= cell[1] < 3 and 0 <= cell[2] < 10):\n                errors.append(f'placed cell outside 3x3x10 pit: {cell}')\n        for seg in segs:\n            for key in ('x1', 'y1', 'x2', 'y2'):\n                val = seg.get(key)\n                if not isinstance(val, int) or not 0 <= val <= 255:\n                    errors.append(f'segment endpoint {key} out of C64 byte range: {val}')\n    summary = report.get('summary', {})\n    if summary.get('totalProjectedLineSegments') != total_segments:\n        errors.append('summary totalProjectedLineSegments must equal actual segment count')\n    if summary.get('maxProjectedLineSegmentsPerOrientation') != max_segments:\n        errors.append('summary maxProjectedLineSegmentsPerOrientation must equal actual max')\n\nif errors:\n    print('ERROR: P03_ELBOW true-axis endpoint 3x3 dotted-pit payload report verification failed.')\n    for err in errors:\n        print(f'- {err}')\n    raise SystemExit(1)\nprint('OK: P03_ELBOW true-axis endpoint 3x3 dotted-pit payload report verified.')\n